#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld", &N);
        long long ans = (N + 1) / 2;
        printf("%lld\n", ans);
    }
    return 0;
}

